# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def build_rows(questions: list[dict]) -> list[dict]:
    """Convert question dicts into DB-ready row bundles."""
    bundles = []
    for q in questions:
        qid = _qid(q["passage_id"])
        diff_int = DIFF_LABEL_TO_INT[q["difficulty"]]
        tag_id = SKILL_TO_TAG[q["skill"]]

        q_row = {
            "id": qid,
            "passage_id": q["passage_id"],
            "stem": q["stem"],
            "difficulty": diff_int,
            "source": SOURCE_TAG,
            "is_active": True,
            "critique_score": q.get("critique_score", 8),
        }

        opt_rows = []
        for i, opt in enumerate(q["options"]):
            opt_rows.append({
                "id": f"{qid}-opt{i}",
                "question_id": qid,
                "text": opt["text"],
                "is_correct": opt["is_correct"],
                "explanation": opt["explanation"],
            })

        tag_rows = [{"question_id": qid, "tag_id": tag_id}]
        # cross-passage gets extra comparison tag
        if q.get("cross_passage"):
            tag_rows.append({"question_id": qid, "tag_id": "t-comparison"})

        bundles.append({
            "question": q_row,
            "options": opt_rows,
            "tags": tag_rows,
            "meta": {
                "passage": q["passage_id"],
                "cross_passage": q.get("cross_passage"),
                "difficulty": q["difficulty"],
                "skill": q["skill"],
                "stem_preview": q["stem"][:40],
            },
        })

    return bundles


def dry_run(bundles: list[dict]) -> None:
    """Pretty-print all questions as JSON for review."""
    print(f"\n{'='*70}")
    print(f"  DRY RUN — {len(bundles)} questions generated (v2 — dedup-revised)")
    print(f"{'='*70}\n")

    for i, b in enumerate(bundles, 1):
        m = b["meta"]
        print(f"── Q{i:02d}  {m['passage']}"
              f"{'→'+m['cross_passage'] if m['cross_passage'] else ''}"
              f"  {m['difficulty']}  {m['skill']} ──")
        print(f"  ID: {b['question']['id']}")
        print(f"  Stem: {b['question']['stem']}")
        for opt in b["options"]:
            mark = "✓" if opt["is_correct"] else "✗"
            print(f"    [{mark}] {opt['text']}")
            print(f"        → {opt['explanation'][:60]}…")
        print(f"  Score: {b['question']['critique_score']}")
        print()

    # Summary stats
    passages = {}
    difficulties = {}
    skills = {}
    for b in bundles:
        m = b["meta"]
        passages[m["passage"]] = passages.get(m["passage"], 0) + 1
        difficulties[m["difficulty"]] = difficulties.get(m["difficulty"], 0) + 1
        skills[m["skill"]] = skills.get(m["skill"], 0) + 1

    print(f"{'='*70}")
    print("  DISTRIBUTION SUMMARY")
    print(f"{'='*70}")
    print(f"  By Passage:    {json.dumps(passages, ensure_ascii=False)}")
    print(f"  By Difficulty:  {json.dumps(difficulties, ensure_ascii=False)}")
    print(f"  By Skill:      {json.dumps(skills, ensure_ascii=False)}")
    print()


def write_to_supabase(bundles: list[dict]) -> None:
    """Write only NEW questions to Supabase (skips stems already in DB).

    Optimised: only fetches existing stems for the passage_ids present
    in the current batch, not the entire database.
    """
    # Add project root to path so we can import mcq_gen
    sys.path.insert(0, str(Path(__file__).parent))
    from mcq_gen.db.client import get_supabase  # noqa: E402

    sb = get_supabase()

    # ── Fetch existing stems — ONLY for relevant passages ──
    batch_passages = list({b["meta"]["passage"] for b in bundles})
    print(f"  Fetching existing stems for passages: {batch_passages}")
    existing = (
        sb.table("dsemcq_questions")
        .select("stem")
        .eq("source", SOURCE_TAG)
        .eq("is_active", True)
        .in_("passage_id", batch_passages)
        .execute()
    )
    existing_stems: set[str] = {r["stem"] for r in existing.data}
    print(f"  Found {len(existing_stems)} existing stems for these passages.")

    written = 0
    skipped = 0

    for i, b in enumerate(bundles, 1):
        # Skip if stem already exists in DB
        if b["question"]["stem"] in existing_stems:
            skipped += 1
            continue

        # 1. Question
        sb.table("dsemcq_questions").insert(b["question"]).execute()

        # 2. Options
        sb.table("dsemcq_question_options").insert(b["options"]).execute()

        # 3. Tags
        for tag in b["tags"]:
            sb.table("dsemcq_question_tags").insert(tag).execute()

        print(f"  Q{i:03d} ✓  {b['question']['id']}  {b['meta']['stem_preview']}")
        written += 1

    print(f"\nDone: {written} written, {skipped} skipped (already in DB).")


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Batch insert MC questions")
    parser.add_argument("--dry-run", action="store_true", help="Print questions only, no DB write")
    parser.add_argument("--all", action="store_true",
                        help="Process ALL questions (not just new ones)")
    parser.add_argument("--from-index", type=int, default=None,
                        help="Override PROCESSED_UP_TO; process from this index")
    args = parser.parse_args()

    start = 0 if args.all else (args.from_index if args.from_index is not None else PROCESSED_UP_TO)
    subset = QUESTIONS[start:]
    if not subset:
        print(f"No new questions to process (PROCESSED_UP_TO={PROCESSED_UP_TO}, total={len(QUESTIONS)}).")
        print("Use --all to process everything, or --from-index N to override.")
        sys.exit(0)

    print(f"Processing {len(subset)} questions (index {start}..{len(QUESTIONS)-1} of {len(QUESTIONS)} total)")
    bundles = build_rows(subset)

    if args.dry_run:
        dry_run(bundles)
    else:
        print(f"Writing {len(bundles)} questions to Supabase…")
        write_to_supabase(bundles)
